<script lang="ts">
	import { goto } from '$app/navigation';
	import { getContext, onMount } from 'svelte';
	import { toast } from 'svelte-sonner';
	import { user } from '$lib/stores';
	import {
		deleteMediaGalleryItem,
		listMediaGalleryItems,
		type MediaGalleryItem,
		type MediaGalleryKind
	} from '$lib/apis/gpthub';

	const i18n = getContext('i18n') as { t?: (key: string) => string } | undefined;
	const t = (key: string) => i18n?.t?.(key) ?? key;

	let items: MediaGalleryItem[] = [];
	let loading = false;
	let deletingId = '';
	let search = '';
	let kind: '' | MediaGalleryKind = '';
	let page = 1;
	let pageSize = 24;
	let total = 0;

	$: totalPages = Math.max(1, Math.ceil(total / pageSize));
	$: canPrev = page > 1;
	$: canNext = page < totalPages;

	const loadItems = async () => {
		if (!$user?.id) return;
		loading = true;
		try {
			const response = await listMediaGalleryItems(localStorage.token, $user.id, {
				page,
				page_size: pageSize,
				kind: kind || undefined,
				search: search.trim() || undefined
			});
			items = response.items ?? [];
			total = response.total ?? 0;
		} catch (error) {
			console.error(error);
			toast.error(t('Failed to load media gallery'));
		} finally {
			loading = false;
		}
	};

	const goToChat = async (item: MediaGalleryItem) => {
		const targetId = item.chat_id || item.thread_id;
		if (!targetId) {
			toast.error(t('Chat reference not available'));
			return;
		}
		const query = item.message_id ? `?message_id=${encodeURIComponent(item.message_id)}` : '';
		await goto(`/c/${targetId}${query}`);
	};

	const removeItem = async (item: MediaGalleryItem) => {
		if (!$user?.id) return;
		deletingId = item.id;
		try {
			await deleteMediaGalleryItem(localStorage.token, $user.id, item.id);
			toast.success(t('Item removed from gallery'));
			await loadItems();
		} catch (error) {
			console.error(error);
			toast.error(t('Failed to delete gallery item'));
		} finally {
			deletingId = '';
		}
	};

	onMount(async () => {
		await loadItems();
	});
</script>

<div class="flex flex-col h-full min-h-0 gap-3">
	<div class="flex flex-col lg:flex-row lg:items-center gap-2">
		<input
			class="w-full lg:max-w-md bg-transparent border rounded-lg px-3 py-2"
			placeholder={t('Search prompt or URL')}
			bind:value={search}
			on:keydown={(event) => {
				if (event.key === 'Enter') {
					page = 1;
					loadItems();
				}
			}}
		/>
		<select
			class="bg-transparent border rounded-lg px-3 py-2"
			bind:value={kind}
			on:change={() => {
				page = 1;
				loadItems();
			}}
		>
			<option value="">{t('All types')}</option>
			<option value="upload">upload</option>
			<option value="generated">generated</option>
		</select>
		<button
			type="button"
			class="px-3 py-2 rounded-lg bg-black text-white dark:bg-white dark:text-black disabled:opacity-50"
			disabled={loading}
			on:click={() => {
				page = 1;
				loadItems();
			}}
		>
			{t('Refresh')}
		</button>
	</div>

	<div class="flex-1 min-h-0">
		{#if loading}
			<div class="text-sm text-gray-500">{t('Loading...')}</div>
		{:else if items.length === 0}
			<div class="text-sm text-gray-500">{t('No media found')}</div>
		{:else}
			<div
				data-gallery-grid
				class="h-full grid grid-cols-1 sm:[grid-template-columns:repeat(auto-fit,minmax(22rem,22rem))] sm:justify-center gap-3 overflow-y-auto pr-1 pb-1 items-start"
			>
				{#each items as item (item.id)}
					<div
						data-gallery-card
						class="w-full max-w-[22rem] mx-auto border border-gray-200 dark:border-gray-800 rounded-xl overflow-hidden flex flex-col"
					>
						<div class="aspect-[4/3] bg-gray-100 dark:bg-gray-900">
							<img
								class="w-full h-full object-cover"
								src={item.thumbnail_url || item.media_url}
								alt={item.kind}
							/>
						</div>
						<div class="p-3 space-y-2 text-xs">
							<div class="flex items-center justify-between">
								<span class="font-medium">{item.kind}</span>
								<span class="text-gray-500">{new Date(item.created_at).toLocaleString()}</span>
							</div>
							<div class="text-gray-500 line-clamp-2">{item.prompt_text || '-'}</div>
							<div class="text-gray-500 truncate">{item.model_id || '-'}</div>
							<div class="flex items-center gap-2">
								<button
									type="button"
									class="px-2 py-1 rounded border border-gray-300 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-900"
									on:click={() => goToChat(item)}
								>
									{t('Go to chat')}
								</button>
								<button
									type="button"
									class="px-2 py-1 rounded border border-red-300 text-red-600 dark:border-red-800 hover:bg-red-50 dark:hover:bg-red-950/20 disabled:opacity-50"
									disabled={deletingId === item.id}
									on:click={() => removeItem(item)}
								>
									{t('Delete')}
								</button>
							</div>
						</div>
					</div>
				{/each}
			</div>
		{/if}
	</div>

	<div class="flex items-center justify-end gap-2 text-xs">
		<button
			type="button"
			class="px-2 py-1 rounded border border-gray-300 dark:border-gray-700 disabled:opacity-50"
			disabled={!canPrev || loading}
			on:click={() => {
				page -= 1;
				loadItems();
			}}
		>
			{t('Prev')}
		</button>
		<span>{t('Page')} {page} / {totalPages}</span>
		<button
			type="button"
			class="px-2 py-1 rounded border border-gray-300 dark:border-gray-700 disabled:opacity-50"
			disabled={!canNext || loading}
			on:click={() => {
				page += 1;
				loadItems();
			}}
		>
			{t('Next')}
		</button>
	</div>
</div>
